import{c as s,Q as n,j as t,m as e}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"前端学习路线总览","description":"","frontmatter":{},"headers":[],"relativePath":"webLearning/01-前端学习路线总览.md","filePath":"webLearning/01-前端学习路线总览.md","lastUpdated":1780905095000}'),p={name:"webLearning/01-前端学习路线总览.md"};function l(i,a,d,c,o,r){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="前端学习路线总览" tabindex="-1">前端学习路线总览 <a class="header-anchor" href="#前端学习路线总览" aria-label="Permalink to &quot;前端学习路线总览&quot;">​</a></h1><p>前端系列不要按&quot;框架百科&quot;读。正确顺序是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>浏览器平台与基础能力</span></span>
<span class="line"><span>  -&gt; 选一个主力框架</span></span>
<span class="line"><span>  -&gt; 学工程化闭环</span></span>
<span class="line"><span>  -&gt; 再补性能、安全、跨端和专题</span></span></code></pre></div><p>一句话先记住:<strong>前端工程 = 用浏览器平台交付可交互 UI,再用工程化保证它可维护、可测试、可发布、可观测。</strong></p><hr><h2 id="一、这套系列讲什么" tabindex="-1">一、这套系列讲什么 <a class="header-anchor" href="#一、这套系列讲什么" aria-label="Permalink to &quot;一、这套系列讲什么&quot;">​</a></h2><p>50 篇分成 8 层:</p><table tabindex="0"><thead><tr><th>层</th><th>章节</th><th>解决的问题</th></tr></thead><tbody><tr><td>入口</td><td>01</td><td>建立学习路线,避免被框架名词带跑</td></tr><tr><td>React</td><td>02-10</td><td>现代 React 应用怎么组织</td></tr><tr><td>Vue</td><td>11-17</td><td>Vue / Nuxt 应用怎么组织</td></tr><tr><td>SolidJS</td><td>18-21</td><td>用细粒度响应式反过来理解 UI 更新</td></tr><tr><td>基础</td><td>22-25</td><td>CSS、TypeScript、JS 异步这些硬地基</td></tr><tr><td>工程化</td><td>26-31</td><td>构建、测试、安全、后端接口、数据库、部署</td></tr><tr><td>浏览器与专题</td><td>32-43</td><td>性能、实时、PWA、渲染、Wasm、跨端等生产能力</td></tr><tr><td>工程闭环</td><td>44-50</td><td>架构分层、设计系统、复杂业务组件、契约、可观测性和项目实战</td></tr></tbody></table><p>不要把 50 篇从头硬刷到尾。先按目标选路线。</p><hr><h2 id="二、最推荐路线" tabindex="-1">二、最推荐路线 <a class="header-anchor" href="#二、最推荐路线" aria-label="Permalink to &quot;二、最推荐路线&quot;">​</a></h2><h3 id="react-路线" tabindex="-1">React 路线 <a class="header-anchor" href="#react-路线" aria-label="Permalink to &quot;React 路线&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01</span></span>
<span class="line"><span>-&gt; 22 CSS 布局</span></span>
<span class="line"><span>-&gt; 23 CSS 方案</span></span>
<span class="line"><span>-&gt; 24 TypeScript</span></span>
<span class="line"><span>-&gt; 25 JS 异步</span></span>
<span class="line"><span>-&gt; 02-10 React / Next.js</span></span>
<span class="line"><span>-&gt; 26 构建工具</span></span>
<span class="line"><span>-&gt; 27 测试</span></span>
<span class="line"><span>-&gt; 28 认证与安全</span></span>
<span class="line"><span>-&gt; 31 部署</span></span>
<span class="line"><span>-&gt; 32 性能</span></span>
<span class="line"><span>-&gt; 35 浏览器渲染</span></span>
<span class="line"><span>-&gt; 44-50 工程闭环</span></span></code></pre></div><p>这是最通用的路线。目标不是&quot;会写组件&quot;,而是能独立交付一个业务前端。</p><h3 id="vue-路线" tabindex="-1">Vue 路线 <a class="header-anchor" href="#vue-路线" aria-label="Permalink to &quot;Vue 路线&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01</span></span>
<span class="line"><span>-&gt; 22-25 基础</span></span>
<span class="line"><span>-&gt; 11-17 Vue / Nuxt</span></span>
<span class="line"><span>-&gt; 26-28 工程化、安全、测试</span></span>
<span class="line"><span>-&gt; 31-35 部署、性能、浏览器</span></span>
<span class="line"><span>-&gt; 44-50 工程闭环</span></span></code></pre></div><p>Vue 适合想快速做产品、管理台、中后台和内容站的团队。Nuxt 是 Vue 进入 SSR / 全栈的主入口。</p><h3 id="已有经验补强路线" tabindex="-1">已有经验补强路线 <a class="header-anchor" href="#已有经验补强路线" aria-label="Permalink to &quot;已有经验补强路线&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24 TypeScript</span></span>
<span class="line"><span>-&gt; 25 JS 异步</span></span>
<span class="line"><span>-&gt; 26 构建工具</span></span>
<span class="line"><span>-&gt; 27 测试</span></span>
<span class="line"><span>-&gt; 32 性能</span></span>
<span class="line"><span>-&gt; 35 浏览器渲染</span></span>
<span class="line"><span>-&gt; 44 架构分层</span></span>
<span class="line"><span>-&gt; 48 API 契约</span></span>
<span class="line"><span>-&gt; 49 可观测性</span></span>
<span class="line"><span>-&gt; 40 a11y</span></span>
<span class="line"><span>-&gt; 41 i18n</span></span></code></pre></div><p>很多前端写了几年还卡住,不是不会框架,而是 TS、异步、构建、测试、浏览器性能这些地方不稳。</p><hr><h2 id="三、三条框架线怎么选" tabindex="-1">三、三条框架线怎么选 <a class="header-anchor" href="#三、三条框架线怎么选" aria-label="Permalink to &quot;三、三条框架线怎么选&quot;">​</a></h2><h3 id="react" tabindex="-1">React <a class="header-anchor" href="#react" aria-label="Permalink to &quot;React&quot;">​</a></h3><p>适合:</p><ul><li>招人、生态、组件库、资料都要最大公约数</li><li>要做复杂 Web App、SaaS、管理台</li><li>未来可能接 Next.js、React Native</li></ul><p>主线:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>02 React 心智</span></span>
<span class="line"><span>03 JSX 与组件</span></span>
<span class="line"><span>04 Hooks</span></span>
<span class="line"><span>05 状态管理</span></span>
<span class="line"><span>06 路由</span></span>
<span class="line"><span>07 数据获取</span></span>
<span class="line"><span>08 表单</span></span>
<span class="line"><span>09 性能</span></span>
<span class="line"><span>10 Next.js</span></span></code></pre></div><p>React 的核心心智是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>state 变 -&gt; 组件函数重跑 -&gt; 生成新 UI 描述 -&gt; diff -&gt; 更新 DOM</span></span></code></pre></div><h3 id="vue" tabindex="-1">Vue <a class="header-anchor" href="#vue" aria-label="Permalink to &quot;Vue&quot;">​</a></h3><p>适合:</p><ul><li>喜欢模板和更低上手成本</li><li>做中后台、内容站、产品迭代</li><li>团队希望官方方案更多,少做生态拼装</li></ul><p>主线:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>11 Vue 心智</span></span>
<span class="line"><span>12 模板与指令</span></span>
<span class="line"><span>13 组合式 API</span></span>
<span class="line"><span>14 响应式原理</span></span>
<span class="line"><span>15 Pinia</span></span>
<span class="line"><span>16 Vue Router</span></span>
<span class="line"><span>17 Nuxt</span></span></code></pre></div><p>Vue 的核心心智是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>响应式数据被模板读取 -&gt; 建立依赖 -&gt; 数据变 -&gt; 用到它的视图更新</span></span></code></pre></div><h3 id="solidjs" tabindex="-1">SolidJS <a class="header-anchor" href="#solidjs" aria-label="Permalink to &quot;SolidJS&quot;">​</a></h3><p>适合:</p><ul><li>想理解细粒度响应式</li><li>高频更新 UI、实时数据面板、性能敏感界面</li><li>已懂 React / Vue,想换一个角度看 UI 更新</li></ul><p>主线:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>18 SolidJS 心智</span></span>
<span class="line"><span>19 Signals</span></span>
<span class="line"><span>20 Stores</span></span>
<span class="line"><span>21 SolidStart</span></span></code></pre></div><p>SolidJS 的核心心智是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>组件函数只跑一次 -&gt; signal 直接绑定 DOM 节点 -&gt; 数据变时精确更新</span></span></code></pre></div><p>SolidJS 不建议作为新人第一门主力框架。它更适合做对照组,帮你理解 React 和 Vue 各自的代价。</p><hr><h2 id="四、基础能力不要跳" tabindex="-1">四、基础能力不要跳 <a class="header-anchor" href="#四、基础能力不要跳" aria-label="Permalink to &quot;四、基础能力不要跳&quot;">​</a></h2><h3 id="css" tabindex="-1">CSS <a class="header-anchor" href="#css" aria-label="Permalink to &quot;CSS&quot;">​</a></h3><p>对应 22-23。</p><p>只会组件库不等于会前端。CSS 至少要掌握:</p><ul><li>Flexbox:一维布局</li><li>Grid:二维页面骨架</li><li>响应式布局</li><li>Tailwind / CSS Modules / scoped style 的取舍</li><li>组件样式怎么复用,页面样式怎么约束</li></ul><h3 id="typescript" tabindex="-1">TypeScript <a class="header-anchor" href="#typescript" aria-label="Permalink to &quot;TypeScript&quot;">​</a></h3><p>对应 24。</p><p>前端 TS 不是背类型体操,重点是:</p><ul><li>props、事件、表单、API 返回值怎么建模</li><li>泛型组件和工具类型怎么读</li><li>类型边界怎么放在 API 层和 domain 层</li><li>不要用 <code>any</code> 把系统打穿</li></ul><h3 id="javascript-异步" tabindex="-1">JavaScript 异步 <a class="header-anchor" href="#javascript-异步" aria-label="Permalink to &quot;JavaScript 异步&quot;">​</a></h3><p>对应 25。</p><p>你要能解释:</p><ul><li>Promise / async / await</li><li>microtask / macrotask</li><li>fetch、AbortController、超时和取消</li><li>并发、重试、竞态和 loading 状态</li></ul><p>前端大量 bug 本质是异步状态没管好。</p><hr><h2 id="五、工程化主线" tabindex="-1">五、工程化主线 <a class="header-anchor" href="#五、工程化主线" aria-label="Permalink to &quot;五、工程化主线&quot;">​</a></h2><p>26-31 是把 demo 变成工程:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>26 构建工具       Vite、monorepo、环境变量、产物</span></span>
<span class="line"><span>27 测试体系       Vitest、Testing Library、Playwright</span></span>
<span class="line"><span>28 认证与安全     Session、JWT、OAuth、XSS、CSRF、CSP</span></span>
<span class="line"><span>29 Node.js 后端   BFF、REST API、接口边界</span></span>
<span class="line"><span>30 数据库与 ORM   Prisma / Drizzle,只讲前端闭环需要的部分</span></span>
<span class="line"><span>31 部署与 CI/CD   Docker、GitHub Actions、Vercel、Cloudflare</span></span></code></pre></div><p>这几篇不要求你变成后端工程师,但要求你能把前端项目接到真实后端和真实发布流程里。</p><hr><h2 id="六、生产能力" tabindex="-1">六、生产能力 <a class="header-anchor" href="#六、生产能力" aria-label="Permalink to &quot;六、生产能力&quot;">​</a></h2><p>32-35 是上线后最常见的问题:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>32 Web 性能优化</span></span>
<span class="line"><span>33 WebSocket 与 SSE</span></span>
<span class="line"><span>34 PWA 与 Service Worker</span></span>
<span class="line"><span>35 浏览器渲染原理</span></span></code></pre></div><p>前端生产问题通常不是&quot;组件不会写&quot;,而是:</p><ul><li>首屏慢</li><li>大列表卡</li><li>接口竞态</li><li>状态重复请求</li><li>缓存失效</li><li>离线和刷新异常</li><li>页面看起来能用,但 Lighthouse / Web Vitals 很差</li></ul><hr><h2 id="七、专题怎么学" tabindex="-1">七、专题怎么学 <a class="header-anchor" href="#七、专题怎么学" aria-label="Permalink to &quot;七、专题怎么学&quot;">​</a></h2><p>36-43 按需学:</p><table tabindex="0"><thead><tr><th>章节</th><th>什么时候学</th></tr></thead><tbody><tr><td>36 WebAssembly</td><td>浏览器里跑重计算、图像处理、音视频、已有 C/Rust 代码</td></tr><tr><td>37 Web Components</td><td>组件跨框架复用、设计系统</td></tr><tr><td>38 微前端</td><td>多团队、多应用、历史包袱很重</td></tr><tr><td>39 图形与动画</td><td>Canvas、WebGL、Three.js、可视化</td></tr><tr><td>40 无障碍 a11y</td><td>面向公众、政企、国际产品</td></tr><tr><td>41 国际化 i18n</td><td>多语言、多地区、时区和格式化</td></tr><tr><td>42 Electron 与 Tauri</td><td>Web 技术做桌面端</td></tr><tr><td>43 React Native 与 Capacitor</td><td>Web 团队做移动端</td></tr></tbody></table><p>专题不是主线。没有业务场景时,先知道边界,不要提前深挖。</p><hr><h2 id="八、工程闭环怎么学" tabindex="-1">八、工程闭环怎么学 <a class="header-anchor" href="#八、工程闭环怎么学" aria-label="Permalink to &quot;八、工程闭环怎么学&quot;">​</a></h2><p>44-50 是把前面所有知识放进真实项目:</p><table tabindex="0"><thead><tr><th>章节</th><th>解决的问题</th></tr></thead><tbody><tr><td>44 前端架构与目录分层</td><td>项目变大后代码放哪里</td></tr><tr><td>45 设计系统与组件库工程</td><td>基础组件、token、Storybook、版本纪律</td></tr><tr><td>46 复杂表格、筛选与批量操作</td><td>中后台列表页的完整模型</td></tr><tr><td>47 文件上传、导入导出与富文本</td><td>文件、Excel、富文本这类高风险功能</td></tr><tr><td>48 API 契约、数据校验与类型生成</td><td>前后端接口如何不靠口头约定</td></tr><tr><td>49 前端可观测性</td><td>错误、性能、埋点、release、requestId</td></tr><tr><td>50 实战项目</td><td>管理台前端闭环</td></tr></tbody></table><p>这 7 篇适合在学完一个主力框架后立刻读。否则你会知道很多 API,但还是不知道真实项目怎么落。</p><hr><h2 id="九、最小闭环" tabindex="-1">九、最小闭环 <a class="header-anchor" href="#九、最小闭环" aria-label="Permalink to &quot;九、最小闭环&quot;">​</a></h2><p>学完以后至少做一个项目:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>登录</span></span>
<span class="line"><span>-&gt; 列表 / 详情 / 表单</span></span>
<span class="line"><span>-&gt; 服务端数据缓存</span></span>
<span class="line"><span>-&gt; 权限</span></span>
<span class="line"><span>-&gt; 文件上传</span></span>
<span class="line"><span>-&gt; E2E 测试</span></span>
<span class="line"><span>-&gt; 部署</span></span>
<span class="line"><span>-&gt; 性能检查</span></span></code></pre></div><p>能完成这个闭环,才算真的会前端。只刷框架 API,很容易停在&quot;会写页面,不会交付系统&quot;。</p><hr><h2 id="十、一句话总结" tabindex="-1">十、一句话总结 <a class="header-anchor" href="#十、一句话总结" aria-label="Permalink to &quot;十、一句话总结&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>React / Vue 是主力生产框架</span></span>
<span class="line"><span>SolidJS 是响应式心智对照</span></span>
<span class="line"><span>CSS / TS / JS 异步是地基</span></span>
<span class="line"><span>构建 / 测试 / 安全 / 部署决定项目能不能长期维护</span></span>
<span class="line"><span>浏览器性能和专题能力按业务场景补</span></span>
<span class="line"><span>44-50 决定你能不能独立交付和长期维护项目</span></span></code></pre></div>`,88)])])}const b=s(p,[["render",l]]);export{u as __pageData,b as default};
